// Symbolic representation of variables
class Variable {
public:
    std::string name;
    int order;

    Variable(std::string n, int o) : name(n), order(o) {}
};

// Basic operations for symbolic differentiation
class Expression {
public:
    virtual ~Expression() = default;
    virtual Expression* differentiate(const Variable& var) const = 0;
};

class Constant : public Expression {
private:
    double value;
public:
    Constant(double v) : value(v) {}

    Expression* differentiate(const Variable& var) const override {
        return new Constant(0); // Derivative of a constant is 0
    }
};

class VariableExpr : public Expression {
private:
    Variable var;
public:
    VariableExpr(const Variable& v) : var(v) {}

    Expression* differentiate(const Variable& var) const override {
        if (this->var.name == var.name) {
            return new Constant(1); // Derivative of x with respect to x is 1
        } else {
            return new Constant(0); // Derivative of x with respect to y is 0
        }
    }
};

class Operation : public Expression {
protected:
    Expression* left;
    Expression* right;
public:
    Operation(Expression* l, Expression* r) : left(l), right(r) {}

    virtual Expression* differentiate(const Variable& var) const = 0;
};

class Addition : public Operation {
public:
    Addition(Expression* l, Expression* r) : Operation(l, r) {}

    Expression* differentiate(const Variable& var) const override {
        return new Addition(left->differentiate(var), right->differentiate(var));
    }
};

class Multiplication : public Operation {
public:
    Multiplication(Expression* l, Expression* r) : Operation(l, r) {}

    Expression* differentiate(const Variable& var) const override {
        return new Addition(
            new Multiplication(left->differentiate(var), right),
            new Multiplication(left, right->differentiate(var))
        );
    }
};

